import React, { useState } from 'react';
import toast from 'react-hot-toast';

const MOCK = [
  { id:1, no:'ENQ001', name:'Riya Gupta',    parent:'Sanjay Gupta',    phone:'9811001100', class_:'Class 6',  source:'Walk-in',   date:'2025-06-05', status:'hot',    remarks:'Very interested, fee structure discussed' },
  { id:2, no:'ENQ002', name:'Rahul Sharma',  parent:'Amit Sharma',     phone:'9822002200', class_:'Class 9',  source:'Phone',     date:'2025-06-04', status:'warm',   remarks:'Called back, wants demo class' },
  { id:3, no:'ENQ003', name:'Pooja Verma',   parent:'Dinesh Verma',    phone:'9833003300', class_:'Class 7',  source:'Reference', date:'2025-06-03', status:'hot',    remarks:'Referred by existing parent' },
  { id:4, no:'ENQ004', name:'Akash Yadav',   parent:'Suresh Yadav',    phone:'9844004400', class_:'Class 11', source:'Website',   date:'2025-06-02', status:'cold',   remarks:'Only checking options' },
  { id:5, no:'ENQ005', name:'Sneha Pandey',  parent:'Vijay Pandey',    phone:'9855005500', class_:'Class 8',  source:'Walk-in',   date:'2025-06-01', status:'warm',   remarks:'Requested school visit' },
  { id:6, no:'ENQ006', name:'Manish Kumar',  parent:'Ajay Kumar',      phone:'9866006600', class_:'Class 10', source:'Phone',     date:'2025-05-31', status:'converted', remarks:'Converted to registration' },
];

const STATUS = {
  hot:       { bg:'#FEE2E2', c:'#991B1B', label:'🔥 Hot Lead'    },
  warm:      { bg:'#FEF3C7', c:'#92400E', label:'🌡️ Warm Lead'   },
  cold:      { bg:'#E0F2FE', c:'#0369A1', label:'🧊 Cold Lead'   },
  converted: { bg:'#D1FAE5', c:'#065F46', label:'✅ Converted'   },
};

const inp = { width:'100%', padding:'9px 12px', border:'1.5px solid #E5E7EB', borderRadius:8, fontSize:13, outline:'none', fontFamily:'inherit' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

export default function Enquiry() {
  const [enquiries, setEnquiries] = useState(MOCK);
  const [showAdd, setShowAdd]     = useState(false);
  const [selected, setSelected]   = useState(null);
  const [filterStatus, setFilter] = useState('');
  const [form, setForm] = useState({ name:'', parent:'', phone:'', class_:'', source:'Walk-in', remarks:'', status:'warm' });

  const filtered = enquiries.filter(e => !filterStatus || e.status === filterStatus);

  const handleAdd = (ev) => {
    ev.preventDefault();
    const enq = { ...form, id: enquiries.length+1, no:`ENQ${String(enquiries.length+7).padStart(3,'0')}`, date: new Date().toISOString().split('T')[0] };
    setEnquiries([enq, ...enquiries]);
    toast.success(`Enquiry ${enq.no} created for ${enq.name}`);
    setShowAdd(false);
    setForm({ name:'', parent:'', phone:'', class_:'', source:'Walk-in', remarks:'', status:'warm' });
  };

  const changeStatus = (id, status) => {
    setEnquiries(enquiries.map(e => e.id===id ? {...e, status} : e));
    toast.success(`Status updated to ${STATUS[status].label}`);
  };

  const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Enquiry Management</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Track and convert admissions enquiries</p></div>
        <button onClick={()=>setShowAdd(true)} style={{padding:'8px 18px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Enquiry</button>
      </div>

      {/* Summary pills */}
      <div style={{display:'flex',gap:10,marginBottom:16,flexWrap:'wrap'}}>
        {Object.entries(STATUS).map(([key,{bg,c,label}]) => {
          const count = enquiries.filter(e=>e.status===key).length;
          return <div key={key} onClick={()=>setFilter(filterStatus===key?'':key)} style={{padding:'7px 14px',borderRadius:10,background:filterStatus===key?c:bg,color:filterStatus===key?'#fff':c,fontSize:12,fontWeight:600,cursor:'pointer',border:`1px solid ${c}20`}}>{label}: <strong>{count}</strong></div>;
        })}
        {filterStatus && <button onClick={()=>setFilter('')} style={{padding:'7px 14px',borderRadius:10,background:'#F3F4F6',border:'1px solid #E5E7EB',fontSize:12,cursor:'pointer'}}>Clear filter ✕</button>}
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Enq No','Student','Parent / Phone','Class','Source','Date','Status','Actions'].map(h=>(
              <th key={h} style={{padding:'9px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:600,textTransform:'uppercase',borderBottom:'0.5px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {filtered.map(e => {
              const st = STATUS[e.status] || STATUS.warm;
              return (
                <tr key={e.id} style={{borderBottom:'0.5px solid #F3F4F6',cursor:'pointer'}} onClick={()=>setSelected(selected?.id===e.id?null:e)}>
                  <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{e.no}</td>
                  <td style={{padding:'10px 12px',fontWeight:600}}>{e.name}</td>
                  <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{e.parent}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{e.phone}</div></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.class_}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#EDE9F8',color:'#1E1B4B'}}>{e.source}</span></td>
                  <td style={{padding:'10px 12px',color:'#6B7280'}}>{e.date}</td>
                  <td style={{padding:'10px 12px'}}><span style={{padding:'3px 10px',borderRadius:20,fontSize:11,background:st.bg,color:st.c,fontWeight:600}}>{st.label}</span></td>
                  <td style={{padding:'10px 12px'}} onClick={ev=>ev.stopPropagation()}>
                    <select value={e.status} onChange={ev=>changeStatus(e.id,ev.target.value)}
                      style={{padding:'4px 8px',border:'1px solid #E5E7EB',borderRadius:6,fontSize:11,cursor:'pointer',background:'#fff'}}>
                      <option value="hot">🔥 Hot</option>
                      <option value="warm">🌡️ Warm</option>
                      <option value="cold">🧊 Cold</option>
                      <option value="converted">✅ Converted</option>
                    </select>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Detail panel */}
      {selected && (
        <div style={{marginTop:14,background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:18}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
            <div style={{fontWeight:700,fontSize:14}}>{selected.no} — {selected.name}</div>
            <button onClick={()=>setSelected(null)} style={{background:'none',border:'none',cursor:'pointer',fontSize:18,color:'#9CA3AF'}}>✕</button>
          </div>
          <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:14,marginBottom:12}}>
            {[['Parent',selected.parent],['Phone',selected.phone],['Class',selected.class_],['Source',selected.source],['Date',selected.date],['Status',STATUS[selected.status]?.label]].map(([k,v])=>(
              <div key={k}><div style={{fontSize:10,color:'#9CA3AF',textTransform:'uppercase',fontWeight:700,marginBottom:3}}>{k}</div><div style={{fontSize:13,fontWeight:600}}>{v}</div></div>
            ))}
          </div>
          <div><div style={{fontSize:10,color:'#9CA3AF',textTransform:'uppercase',fontWeight:700,marginBottom:4}}>Remarks</div><div style={{fontSize:13,color:'#374151',padding:'10px 12px',background:'#F9FAFB',borderRadius:8}}>{selected.remarks}</div></div>
          <div style={{display:'flex',gap:10,marginTop:14}}>
            <button onClick={()=>{toast.success(`Converting ${selected.name} to Registration`);setSelected(null);}} style={{padding:'8px 16px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:12,fontWeight:600,cursor:'pointer'}}>Convert to Registration →</button>
            <button onClick={()=>toast.success('Follow-up scheduled!')} style={{padding:'8px 16px',border:'1px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:12,cursor:'pointer'}}>📅 Schedule Follow-up</button>
          </div>
        </div>
      )}

      {/* Add Enquiry Modal */}
      {showAdd && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.45)',zIndex:300,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:520,maxWidth:'100%',overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>📞 New Enquiry</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:7,width:30,height:30,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Student Name <span style={{color:'#DC2626'}}>*</span></label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="Student full name" style={inp}/></div>
                <div><label style={lbl}>Parent Name <span style={{color:'#DC2626'}}>*</span></label><input required value={form.parent} onChange={e=>setForm({...form,parent:e.target.value})} placeholder="Parent/Guardian name" style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Mobile <span style={{color:'#DC2626'}}>*</span></label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} placeholder="10-digit" style={inp}/></div>
                <div><label style={lbl}>Class Interested</label><select value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={inp}><option value="">Select</option>{CLASSES.map(c=><option key={c}>{c}</option>)}</select></div>
                <div><label style={lbl}>Source</label><select value={form.source} onChange={e=>setForm({...form,source:e.target.value})} style={inp}><option>Walk-in</option><option>Phone</option><option>Website</option><option>Reference</option><option>Social Media</option></select></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Lead Status</label><select value={form.status} onChange={e=>setForm({...form,status:e.target.value})} style={inp}><option value="hot">🔥 Hot Lead</option><option value="warm">🌡️ Warm Lead</option><option value="cold">🧊 Cold Lead</option></select></div>
              </div>
              <div style={{marginBottom:16}}><label style={lbl}>Remarks</label><textarea value={form.remarks} onChange={e=>setForm({...form,remarks:e.target.value})} placeholder="Notes about this enquiry…" rows={3} style={{...inp,resize:'vertical'}}/></div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'9px 18px',border:'1.5px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" style={{padding:'9px 22px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:700,cursor:'pointer'}}>💾 Save Enquiry</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
